    $4 == "FUNC" && NF >= 8 {
      start = strtonum("0x"$2)
      size = $3
      if (start <= a && start + size > a) {
        offset = a - start
        printf "%s+0x%x (0x%s)\n", $NF, offset, $2
      }
    }')
  printf "%-12s → %s\n" "$addr" "${match:-<no match>}"
done", "description": "Cross-check all symbols"}

